import{_ as t,o as a,c as e,ae as o}from"./chunks/framework.DrYEjkpc.js";const k=JSON.parse('{"title":"SkillRouter.org","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-skillrouter-org.md","filePath":"radar/tech-skillrouter-org.md"}'),l={name:"radar/tech-skillrouter-org.md"};function i(n,r,s,d,h,u){return a(),e("div",null,[...r[0]||(r[0]=[o('<h1 id="skillrouter-org" tabindex="-1">SkillRouter.org <a class="header-anchor" href="#skillrouter-org" aria-label="Permalink to &quot;SkillRouter.org&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 召回 | <strong>成熟度</strong>: 🔴 探索期（早期） | <strong>综合评分</strong>: 0.38</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: <strong>早期阶段</strong>的 MCP 路由商业服务（当前主要为落地页 / 营销页，未见公开评测与生产用户案例）。</p><p><strong>来源</strong>:</p><ul><li>社区/商业产品（非论文）</li></ul><p><strong>链接</strong>:</p><ul><li>官网：<a href="https://skillrouter.org/" target="_blank" rel="noreferrer">skillrouter.org</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h3><ul><li><strong>MCP Server 即插即用</strong> —— 接入 Claude Code / Cursor 等</li><li>声称&quot;生态级学习优化推荐精度&quot;</li></ul><h3 id="与学术界-skillrouter-的关系" tabindex="-1">与学术界 SkillRouter 的关系 <a class="header-anchor" href="#与学术界-skillrouter-的关系" aria-label="Permalink to &quot;与学术界 SkillRouter 的关系&quot;">​</a></h3><p>注意：<strong>SkillRouter.org</strong>（社区商业产品）与学术论文 <strong>SkillRouter</strong>（arXiv 2603.22455）名称相近但<strong>不是同一项工作</strong>。前者是商业服务，技术细节不透明；后者是论文 + 开源实现。</p><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li><strong>技术细节不透明</strong> —— 路由算法、模型规模、训练数据均未公开</li><li><strong>无公开评测数据</strong> —— 与 SkillRouter 学术工作的 74% Hit@1 不可直接对比</li><li>商业化产品，可能存在 vendor lock-in</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.40</td><td>早期阶段，落地页为主</td></tr><tr><td>创新性</td><td>0.35</td><td>未见公开技术细节</td></tr><tr><td>落地程度</td><td>0.40</td><td>未见公开生产用户案例</td></tr><tr><td>生态活跃度</td><td>0.35</td><td>落地页 / 营销页阶段</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.38</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://skillrouter.org/" target="_blank" rel="noreferrer">skillrouter.org</a></li><li>学术工作（不同项目）：<a href="https://arxiv.org/abs/2603.22455" target="_blank" rel="noreferrer">SkillRouter 论文</a></li></ul>',26)])])}const c=t(l,[["render",i]]);export{k as __pageData,c as default};
